import{_ as i,o as a,c as r,ae as e}from"./chunks/framework.RRduUuAx.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/business/chapter-3.md","filePath":"szu/business/chapter-3.md"}'),t={name:"szu/business/chapter-3.md"};function o(s,l,n,u,h,c){return a(),r("div",null,[...l[0]||(l[0]=[e('<h2 id="第一节-客户关系管理概述" tabindex="-1">第一节 客户关系管理概述 <a class="header-anchor" href="#第一节-客户关系管理概述" aria-label="Permalink to &quot;第一节 客户关系管理概述&quot;">​</a></h2><ol><li>客户关系管理的概念 <ul><li>概念：<strong>客户关系管理（CRM），即企业为提高核心竞争力，通过改进对客户的服务水平，提高客户的满意度和忠诚度，所树立的“以客户为中心”的经营理念。</strong></li><li>特点：1.客户关系管理是一种理念；2.是一种旨在改善企业和客户之间关系的新型管理机制；3.包含一整套解决方案；</li></ul></li><li>客户关系管理产出的背景<br> 20 世纪 90 年代后期 Internet 应用的迅猛发展推动了客户关系管理的产生和发展。<br> 由四个方面推动和促成：经营理念更新的需要；企业管理模式更新的需要；提高核心竞争力的需要；信息技术的推动。</li><li>客户关系管理的意义<br><strong>1.改善营销功能，提升销售业绩；2.降低企业成本，提高运营效率；3.改善客户服务，提高客户满意度；4.优化企业流程，提高市场份额。</strong></li></ol><h2 id="第二节-客户关系管理的流程" tabindex="-1">第二节 客户关系管理的流程 <a class="header-anchor" href="#第二节-客户关系管理的流程" aria-label="Permalink to &quot;第二节 客户关系管理的流程&quot;">​</a></h2><ol><li><strong>客户关系管理的基本流程（超重点）五个阶段</strong><ul><li>客户分析<br><strong>关键是分析客户的终身价值</strong>。客户终生价值是指一个新客户在未来所能给企业带来的期望净现值。一个客户的价值由三个部分组成：<strong>历史价值、当前价值、潜在价值。</strong></li><li>深入了解目标客户</li><li>发展关系网络</li><li>创造客户价值</li><li>管理客户关系</li></ul></li><li>客户关系管理的支持流程<br> 企业文化及企业领导的支持是必要条件；IT 和数据库基础设施是进行数据挖掘和分析的必要信息平台；组织结构和业务流程的重新设计；人力资源管理等的支持。</li></ol><h2 id="第三节-客户关系管理的解决方案" tabindex="-1">第三节 客户关系管理的解决方案 <a class="header-anchor" href="#第三节-客户关系管理的解决方案" aria-label="Permalink to &quot;第三节 客户关系管理的解决方案&quot;">​</a></h2><ol><li>客户关系管理系统的架构<br> 一个完整、有效的客户关系管理应用系统，由<strong>业务操作管理、客户合作管理、数据分析管理、信息技术管理</strong>四个子系统组成。<br> 业务操作管理子系统包括：<strong>营销管理模块、销售管理模块、客户服务模块</strong><ul><li>营销管理模块：具有市场分析、市场预测、市场活动管理功能。</li><li>销售管理模块：实现从报价、订货一直到付款、给付佣金的全程销售的自动化，提高销售的有效性。</li><li>客户服务模块：一般包括四个集成部件：服务、合同、客户关系、移动现场服务</li></ul></li><li>客户关系管理的关键技术 <ul><li>呼叫中心技术<br> 现代真正意义上的呼叫中心要具备如下功能： <ul><li>1.提供 7*24 小时不间断服务，允许顾客与业务代表通信时选择多种通信方式</li><li>2.能事先了解有关顾客的各种信息，对不同用户安排不同业务代表与之交谈。</li><li>3.可以把从用户那里得到的信息，数据，全部存储在数据库中，供企业做分析决策之用。</li><li>4.采用现代化的技术和良好的管理系统，随时可以观察到呼叫中心的运行情况和业务代表的工作情况。</li></ul></li><li>数据仓库</li><li>商业智能</li><li>Web 的集成管理</li></ul></li></ol><h2 id="第四节-客户关系管理的实施" tabindex="-1">第四节 客户关系管理的实施 <a class="header-anchor" href="#第四节-客户关系管理的实施" aria-label="Permalink to &quot;第四节 客户关系管理的实施&quot;">​</a></h2><ol><li><strong>实施客户关系管理的基本步骤（超重点）</strong><ul><li>确立业务计划</li><li>建立客户关系管理项目团队</li><li>分析客户需求，开展信息系统初建</li><li>明确企业应用需求</li><li>为客户关系管理不同级别系统设置优先级</li><li>选择合适的方案</li><li>组织用户培训</li><li>使用，维护，评估和改进</li></ul></li><li>实施客户关系管理的条件 <ul><li>专注于流程，设计长远规划</li><li>遵循专业化、社会化和开放式的运作思维</li><li>着力加强对渠道和应用子系统的集成</li><li>加强支持网络应用的能力</li><li>极大地重视人的因素</li></ul></li></ol><h2 id="识记内容" tabindex="-1">识记内容 <a class="header-anchor" href="#识记内容" aria-label="Permalink to &quot;识记内容&quot;">​</a></h2><ol><li>客户关系管理的定义，客户关系管理的特点。</li><li>客户关系管理价值链的概念。客户关系管理基本流程包含的阶段。客户价值的组成。影响客户终身价值的因素。客户组合分析法。</li><li>客户关系管理系统架构包括的子系统名称。业务操作子系统包括的模块。营销模块的功能。销售模块的组成。客户服务模块的组成。企业与客户互动的渠道。呼叫中心的功能。</li><li>客户关系管理的实施步骤。实施客户关系管理的条件。</li></ol><h2 id="领会内容" tabindex="-1">领会内容 <a class="header-anchor" href="#领会内容" aria-label="Permalink to &quot;领会内容&quot;">​</a></h2><ol><li>客户关系管理的产生背景。客户关系管理的意义。</li><li>客户关系管理中客户分析的具体步骤。客户关系管理支持流程的具体内容。</li><li>客户关系管理的关键技术。</li></ol>',12)])])}const _=i(t,[["render",o]]);export{b as __pageData,_ as default};
